class PaymentProvider(Protocol):
    def charge(self, amount_cents: int, token: str) -> str: ...

class StripeAdapter(PaymentProvider):
    def __init__(self, stripe_client: StripeClient) -> None:
        self._client = stripe_client

    def charge(self, amount_cents: int, token: str) -> str:
        response = self._client.create_payment_intent(
            amount=amount_cents, currency="usd", payment_method=token
        )
        return response.id

class DataStore(Protocol):
    def get(self, key: str) -> Any: ...
    def set(self, key: str, value: Any) -> None: ...

class LoggingDecorator:
    def __init__(self, store: DataStore) -> None:
        self._store = store

    def get(self, key: str) -> Any:
        value = self._store.get(key)
        logger.info("GET key=%s hit=%s", key, value is not None)
        return value

    def set(self, key: str, value: Any) -> None:
        logger.info("SET key=%s", key)
        self._store.set(key, value)

class CachingDecorator:
    def __init__(self, store: DataStore) -> None:
        self._store = store
        self._cache: dict[str, Any] = {}

    def get(self, key: str) -> Any:
        if key not in self._cache:
            self._cache[key] = self._store.get(key)
        return self._cache[key]

    def set(self, key: str, value: Any) -> None:
        self._cache.pop(key, None)
        self._store.set(key, value)

# Stacking: LoggingDecorator wraps CachingDecorator wraps InMemoryStore
store: DataStore = LoggingDecorator(CachingDecorator(InMemoryStore()))

class PaymentFacade:
    def __init__(
        self,
        validator: PaymentValidator | None = None,
        fraud_detector: FraudDetector | None = None,
        gateway: PaymentGatewayClient | None = None,
        ledger: Ledger | None = None,
        notifier: EmailNotifier | None = None,
    ) -> None:
        self._validator = validator or PaymentValidator()
        self._fraud = fraud_detector or FraudDetector()
        self._gateway = gateway or PaymentGatewayClient()
        self._ledger = ledger or Ledger()
        self._notifier = notifier or EmailNotifier()

    def charge(
        self,
        user_id: str,
        card_token: str,
        amount_cents: int,
        idempotency_key: str,
        ip: str = "0.0.0.0",
    ) -> ChargeResult:
        """Complete payment: validate → fraud check → charge → ledger → notify."""
        if not self._validator.validate_card(card_token):
            self._ledger.record_failure(user_id, amount_cents, "invalid_card")
            return ChargeResult(success=False, error="invalid_card")

        if not self._validator.validate_amount(amount_cents):
            return ChargeResult(success=False, error="invalid_amount")

        if not self._fraud.check(user_id, amount_cents, ip):
            self._ledger.record_failure(user_id, amount_cents, "fraud_detected")
            return ChargeResult(success=False, error="fraud_detected")

        tx_id = self._gateway.charge(card_token, amount_cents, idempotency_key)
        self._ledger.record_charge(user_id, amount_cents, tx_id)
        self._notifier.send_receipt(user_id, amount_cents, tx_id)

        return ChargeResult(success=True, transaction_id=tx_id)

class LazyImageProxy:
    def __init__(self, file_path: str) -> None:
        self._file_path = file_path
        self._real_image: HighResImage | None = None

    def _load(self) -> HighResImage:
        if self._real_image is None:
            self._real_image = HighResImage(self._file_path)
        return self._real_image

    def render(self) -> str:
        return self._load().render()

    def dimensions(self) -> tuple[int, int]:
        return self._load().dimensions()

class DatabaseQueryProxy:
    def __init__(self, db_executor) -> None:
        self._executor = db_executor
        self._cache: dict[str, object] = {}

    def execute(self, query: str, params: tuple = ()) -> object:
        cache_key = f"{query}:{params}"
        if cache_key not in self._cache:
            self._cache[cache_key] = self._executor.execute(query, params)
        else:
            print(f"[CacheProxy] Cache hit")
        return self._cache[cache_key]

    def invalidate(self, pattern: str) -> None:
        """Invalidate cache entries matching a pattern prefix."""
        keys_to_remove = [k for k in self._cache if k.startswith(pattern)]
        for k in keys_to_remove:
            del self._cache[k]
